+    let task_id = setup_leaked_obligation(&mut state);
+    let _ = state.task_completed(task_id);
+
+    assert_eq!(provider.obligations_leaked.load(Ordering::SeqCst), 1);
+    assert!(trace_has_obligation_leak(&state));
+}
+
+#[test]
